function findAnagrams(s, p) {
  const result = [];
  if (s.length < p.length) return result;

  // Create frequency map for pattern
  const pMap = {};
  for (let char of p) {
    pMap[char] = (pMap[char] || 0) + 1;
  }

  // Create frequency map for sliding window
  const sMap = {};
  const windowSize = p.length;

  // Initialize first window
  for (let i = 0; i < windowSize; i++) {
    sMap[s[i]] = (sMap[s[i]] || 0) + 1;
  }

  // Helper function to compare maps
  const mapsEqual = (map1, map2) => {
    if (Object.keys(map1).length !== Object.keys(map2).length) return false;
    for (let key in map1) {
      if (map1[key] !== map2[key]) return false;
    }
    return true;
  };

  // Check first window
  if (mapsEqual(sMap, pMap)) result.push(0);

  // Slide the window
  for (let i = windowSize; i < s.length; i++) {
    // Add new character to window
    sMap[s[i]] = (sMap[s[i]] || 0) + 1;

    // Remove old character from window
    const oldChar = s[i - windowSize];
    sMap[oldChar]--;
    if (sMap[oldChar] === 0) delete sMap[oldChar];

    // Check if current window is an anagram
    if (mapsEqual(sMap, pMap)) {
      result.push(i - windowSize + 1);
    }
  }

  return result;
}
